165→const DEFAULT_STAT_OPTIONS: StatOptions = {
166→  minimapType: "area",
167→  reducer: "last",
168→  format: "short_number",
169→};
170→
171→const DEFAULT_TIMESERIES_OPTIONS: TimeseriesOptions = {
172→  legendPlacement: "bottom",
173→  yAxisFormat: "short_number",
174→  stacked: false,
175→};
176→
177→const DEFAULT_PIE_OPTIONS: PieOptions = {
178→  legendPlacement: "right",
179→  labelFormat: "name-percent",
180→};
181→
182→const DEFAULT_GAUGE_OPTIONS: GaugeOptions = {
183→  min: 0,
184→  max: 100,
185→  valueFormat: "",
186→};
187→
188→const DEFAULT_TABLE_OPTIONS: TableOptions = {
189→  stickyHeader: false,
190→  serverSideSorting: false,
191→};
