193→export interface PanelEditState {
194→  chartType: ChartType;
195→  title: string;
196→  sql: string;
197→  gridW: number;
198→  gridH: number;
199→
200→  statOptions: StatOptions;
201→  timeseriesOptions: TimeseriesOptions;
202→  pieOptions: PieOptions;
203→  gaugeOptions: GaugeOptions;
204→  tableOptions: TableOptions;
205→
206→  previewDescriptor: PanelDescriptor | null;
207→  previewKey: number;
208→  isDirty: boolean;
209→}
210→
211→export function usePanelEditState(editingPanel?: PanelDescriptor | null) {
212→  // Preserved original descriptor for merging non-UI options
213→  const originalDescriptorRef = useRef<PanelDescriptor | null>(
214→    editingPanel ?? null
215→  );
216→
217→  const [chartType, setChartTypeState] = useState<ChartType>(() =>
218→    editingPanel ? (editingPanel.type as ChartType) : "line"
219→  );
220→  const [title, setTitleState] = useState(
221→    () => editingPanel?.titleOption?.title ?? ""
222→  );
223→  const [sql, setSqlState] = useState(
224→    () => editingPanel?.datasource?.sql ?? ""
225→  );
226→  const [gridW, setGridW] = useState(() => editingPanel?.gridPos?.w ?? 12);
227→  const [gridH, setGridH] = useState(() => editingPanel?.gridPos?.h ?? 6);
228→
229→  const [statOptions, setStatOptions] = useState<StatOptions>(() =>
230→    extractStatOptions(editingPanel)
231→  );
232→  const [timeseriesOptions, setTimeseriesOptions] =
233→    useState<TimeseriesOptions>(() =>
234→      extractTimeseriesOptions(editingPanel)
235→    );
236→  const [pieOptions, setPieOptions] = useState<PieOptions>(() =>
237→    extractPieOptions(editingPanel)
238→  );
239→  const [gaugeOptions, setGaugeOptions] = useState<GaugeOptions>(() =>
240→    extractGaugeOptions(editingPanel)
241→  );
242→  const [tableOptions, setTableOptions] = useState<TableOptions>(() =>
243→    extractTableOptions(editingPanel)
244→  );
245→
246→  const [previewDescriptor, setPreviewDescriptor] =
247→    useState<PanelDescriptor | null>(() =>
248→      editingPanel ? buildDescriptorFromState(
249→        editingPanel.type as ChartType,
250→        editingPanel.titleOption?.title ?? "",
251→        editingPanel.datasource?.sql ?? "",
252→        editingPanel.gridPos?.w ?? 12,
253→        editingPanel.gridPos?.h ?? 6,
254→        extractStatOptions(editingPanel),
255→        extractTimeseriesOptions(editingPanel),
256→        extractPieOptions(editingPanel),
257→        extractGaugeOptions(editingPanel),
258→        extractTableOptions(editingPanel),
259→        editingPanel
260→      ) : null
261→    );
262→  const [previewKey, setPreviewKey] = useState(0);
263→  const [isDirty, setIsDirty] = useState(false);
264→
265→  const markDirty = useCallback(() => setIsDirty(true), []);
266→
267→  const setTitle = useCallback(
268→    (value: string) => {
269→      setTitleState(value);
270→      markDirty();
271→    },
272→    [markDirty]
273→  );
274→
275→  const setSql = useCallback(
276→    (value: string) => {
277→      setSqlState(value);
278→      markDirty();
279→    },
280→    [markDirty]
281→  );
282→
283→  const setChartType = useCallback(
284→    (type: ChartType) => {
285→      setChartTypeState(type);
286→      markDirty();
287→    },
288→    [markDirty]
289→  );
290→
291→  const setGridSize = useCallback(
292→    (w: number, h: number) => {
293→      setGridW(w);
294→      setGridH(h);
295→      markDirty();
296→    },
297→    [markDirty]
298→  );
299→
300→  const updateStatOptions = useCallback(
301→    (partial: Partial<StatOptions>) => {
302→      setStatOptions((prev) => ({ ...prev, ...partial }));
303→      markDirty();
304→    },
305→    [markDirty]
306→  );
307→
308→  const updateTimeseriesOptions = useCallback(
309→    (partial: Partial<TimeseriesOptions>) => {
310→      setTimeseriesOptions((prev) => ({ ...prev, ...partial }));
311→      markDirty();
312→    },
313→    [markDirty]
314→  );
315→
316→  const updatePieOptions = useCallback(
317→    (partial: Partial<PieOptions>) => {
318→      setPieOptions((prev) => ({ ...prev, ...partial }));
319→      markDirty();
320→    },
321→    [markDirty]
322→  );
323→
324→  const updateGaugeOptions = useCallback(
325→    (partial: Partial<GaugeOptions>) => {
326→      setGaugeOptions((prev) => ({ ...prev, ...partial }));
327→      markDirty();
328→    },
329→    [markDirty]
330→  );
331→
332→  const updateTableOptions = useCallback(
333→    (partial: Partial<TableOptions>) => {
334→      setTableOptions((prev) => ({ ...prev, ...partial }));
335→      markDirty();
336→    },
337→    [markDirty]
338→  );
339→
340→  const runQuery = useCallback(() => {
341→    const descriptor = buildDescriptorFromState(
342→      chartType,
343→      title,
344→      sql,
345→      gridW,
346→      gridH,
347→      statOptions,
348→      timeseriesOptions,
349→      pieOptions,
350→      gaugeOptions,
351→      tableOptions,
352→      originalDescriptorRef.current
353→    );
354→    setPreviewDescriptor(descriptor);
355→    setPreviewKey((k) => k + 1);
356→  }, [
357→    chartType,
358→    title,
359→    sql,
360→    gridW,
361→    gridH,
362→    statOptions,
363→    timeseriesOptions,
364→    pieOptions,
365→    gaugeOptions,
366→    tableOptions,
367→  ]);
368→
369→  const buildDescriptor = useCallback((): PanelDescriptor | null => {
370→    if (!title.trim() || !sql.trim()) return null;
371→    return buildDescriptorFromState(
372→      chartType,
373→      title,
374→      sql,
375→      gridW,
376→      gridH,
377→      statOptions,
378→      timeseriesOptions,
379→      pieOptions,
380→      gaugeOptions,
381→      tableOptions,
382→      originalDescriptorRef.current
383→    );
384→  }, [
385→    chartType,
386→    title,
387→    sql,
388→    gridW,
389→    gridH,
390→    statOptions,
391→    timeseriesOptions,
392→    pieOptions,
393→    gaugeOptions,
394→    tableOptions,
395→  ]);
396→
397→  const applyTemplate = useCallback(
398→    (template: WidgetTemplate) => {
399→      setChartTypeState(template.chartType);
400→      setTitleState(template.name);
401→      setSqlState(template.sql);
402→      setGridW(template.gridW);
403→      setGridH(template.gridH);
404→      markDirty();
405→    },
406→    [markDirty]
407→  );
408→
409→  const isValid = title.trim().length > 0 && sql.trim().length > 0;
410→
411→  return {
412→    // State
413→    chartType,
414→    title,
415→    sql,
416→    gridW,
417→    gridH,
418→    statOptions,
419→    timeseriesOptions,
420→    pieOptions,
421→    gaugeOptions,
422→    tableOptions,
423→    previewDescriptor,
424→    previewKey,
425→    isDirty,
426→    isValid,
427→
428→    // Actions
429→    setChartType,
430→    setTitle,
431→    setSql,
432→    setGridSize,
433→    updateStatOptions,
434→    updateTimeseriesOptions,
435→    updatePieOptions,
436→    updateGaugeOptions,
437→    updateTableOptions,
438→    runQuery,
439→    buildDescriptor,
440→    applyTemplate,
441→  };
442→}
443→
444→// --- Helper functions ---
445→
446→function extractStatOptions(
447→  panel?: PanelDescriptor | null
448→): StatOptions {
449→  if (!panel || panel.type !== "stat") return DEFAULT_STAT_OPTIONS;
450→  const d = panel as StatDescriptor;
451→  return {
452→    minimapType: d.minimapOption?.type ?? "area",
453→    reducer: d.valueOption?.reducer ?? "last",
454→    format: d.valueOption?.format ?? "short_number",
455→  };
456→}
457→
458→function extractTimeseriesOptions(
459→  panel?: PanelDescriptor | null
460→): TimeseriesOptions {
461→  if (
462→    !panel ||
463→    (panel.type !== "line" && panel.type !== "bar" && panel.type !== "area")
464→  )
465→    return DEFAULT_TIMESERIES_OPTIONS;
466→  const d = panel as TimeseriesDescriptor;
467→  return {
468→    legendPlacement: d.legendOption?.placement ?? "bottom",
469→    yAxisFormat: d.yAxis?.[0]?.format ?? "short_number",
470→    stacked: d.stacked ?? false,
471→  };
472→}
473→
474→function extractPieOptions(
475→  panel?: PanelDescriptor | null
476→): PieOptions {
477→  if (!panel || panel.type !== "pie") return DEFAULT_PIE_OPTIONS;
478→  const d = panel as PieDescriptor;
479→  return {
480→    legendPlacement: d.legendOption?.placement ?? "right",
481→    labelFormat: d.labelOption?.format ?? "name-percent",
482→  };
483→}
484→
485→function extractGaugeOptions(
486→  panel?: PanelDescriptor | null
487→): GaugeOptions {
488→  if (!panel || panel.type !== "gauge") return DEFAULT_GAUGE_OPTIONS;
489→  const d = panel as GaugeDescriptor;
490→  return {
491→    min: d.gaugeOption?.min ?? 0,
492→    max: d.gaugeOption?.max ?? 100,
493→    valueFormat: d.gaugeOption?.valueFormat ?? "",
494→  };
495→}
496→
497→function extractTableOptions(
498→  panel?: PanelDescriptor | null
499→): TableOptions {
500→  if (!panel || panel.type !== "table") return DEFAULT_TABLE_OPTIONS;
501→  const d = panel as TableDescriptor;
502→  return {
503→    stickyHeader: d.headOption?.isSticky ?? false,
504→    serverSideSorting: d.sortOption?.serverSideSorting ?? false,
505→  };
506→}
507→
508→function buildDescriptorFromState(
509→  chartType: ChartType,
510→  title: string,
511→  sql: string,
512→  gridW: number,
513→  gridH: number,
514→  statOpts: StatOptions,
515→  timeseriesOpts: TimeseriesOptions,
516→  pieOpts: PieOptions,
517→  gaugeOpts: GaugeOptions,
518→  tableOpts: TableOptions,
519→  originalDescriptor?: PanelDescriptor | null
520→): PanelDescriptor {
521→  const gridPos: GridPos = { w: gridW, h: gridH };
522→
523→  const base: PanelDescriptor = {
524→    type: chartType,
525→    titleOption: { title: title.trim() },
526→    gridPos,
527→    datasource: { sql: sql.trim() },
528→  };
529→
530→  // Preserve any fields from the original descriptor that aren't managed by the UI
531→  switch (chartType) {
532→    case "stat": {
533→      const original = originalDescriptor?.type === "stat"
534→        ? (originalDescriptor as StatDescriptor)
535→        : undefined;
536→      return {
537→        ...base,
538→        type: "stat",
539→        minimapOption: { type: statOpts.minimapType },
540→        valueOption: {
541→          ...original?.valueOption,
542→          reducer: statOpts.reducer,
543→          format: statOpts.format as any,
544→        },
545→        comparisonOption: original?.comparisonOption,
546→      } as StatDescriptor;
547→    }
548→    case "line":
549→    case "bar":
550→    case "area": {
551→      const original =
552→        originalDescriptor?.type === chartType
553→          ? (originalDescriptor as TimeseriesDescriptor)
554→          : undefined;
555→      return {
556→        ...base,
557→        type: chartType,
558→        legendOption: { placement: timeseriesOpts.legendPlacement },
559→        yAxis: [
560→          {
561→            ...original?.yAxis?.[0],
562→            format: timeseriesOpts.yAxisFormat as any,
563→          },
564→        ],
565→        tooltipOption: original?.tooltipOption,
566→        stacked: timeseriesOpts.stacked,
567→        fieldOptions: original?.fieldOptions,
568→      } as TimeseriesDescriptor;
569→    }
570→    case "pie": {
571→      const original =
572→        originalDescriptor?.type === "pie"
573→          ? (originalDescriptor as PieDescriptor)
574→          : undefined;
575→      return {
576→        ...base,
577→        type: "pie",
578→        legendOption: { placement: pieOpts.legendPlacement },
579→        labelOption: {
580→          show: true,
581→          format: pieOpts.labelFormat,
582→        },
583→        valueFormat: original?.valueFormat,
584→        fieldOptions: original?.fieldOptions,
585→      } as PieDescriptor;
586→    }
587→    case "gauge": {
588→      const original =
589→        originalDescriptor?.type === "gauge"
590→          ? (originalDescriptor as GaugeDescriptor)
591→          : undefined;
592→      return {
593→        ...base,
594→        type: "gauge",
595→        gaugeOption: {
596→          ...original?.gaugeOption,
597→          min: gaugeOpts.min,
598→          max: gaugeOpts.max,
599→          valueFormat: gaugeOpts.valueFormat as any,
600→        },
601→        fieldOptions: original?.fieldOptions,
602→      } as GaugeDescriptor;
603→    }
604→    case "table": {
605→      const original =
606→        originalDescriptor?.type === "table"
607→          ? (originalDescriptor as TableDescriptor)
608→          : undefined;
609→      return {
610→        ...base,
611→        type: "table",
612→        headOption: { isSticky: tableOpts.stickyHeader },
613→        sortOption: {
614→          ...original?.sortOption,
615→          serverSideSorting: tableOpts.serverSideSorting,
616→        },
617→        fieldOptions: original?.fieldOptions,
618→        pagination: original?.pagination,
619→        miscOption: original?.miscOption,
620→        actions: original?.actions,
621→      } as TableDescriptor;
622→    }
623→    default:
624→      return base;
625→  }
626→}
