105→const normalizeVisualizationError = (message: string) => {
106→  if (message.includes("Missing columns:") || message.includes("UNKNOWN_IDENTIFIER")) {
107→    return "no metrics";
108→  }
109→  return message;
110→};
111→
112→interface DashboardVisualizationPanelProps {
113→  descriptor: PanelDescriptor;
114→  initialTimeSpan?: TimeSpan;
115→  initialFilterExpression?: string;
116→  initialLoading?: boolean;
117→  onCollapsedChange?: (isCollapsed: boolean) => void;
118→  onChartSelection?: (
119→    timeSpan: TimeSpan,
120→    { name, series, value }: { name: string; series: string; value: number }
121→  ) => void;
122→  className?: string;
123→}
124→
125→export const DashboardVisualizationPanel = forwardRef<
126→  DashboardVisualizationComponent,
127→  DashboardVisualizationPanelProps
128→>(function DashboardVisualizationPanel(props, ref) {
129→  const { descriptor, initialLoading = true, onCollapsedChange } = props;
130→
131→  // Type narrowing for refactored visualization types
132→  const typedDescriptor = descriptor as
133→    | TableDescriptor
134→    | PieDescriptor
135→    | TransposeTableDescriptor
136→    | TimeseriesDescriptor
137→    | GaugeDescriptor
138→    | StatDescriptor;
139→
140→  const { connection } = useConnection();
141→  const customDashboardActions = useCustomDashboardActions();
142→
143→  // State - unified for all visualization types
144→  const [data, setData] = useState<Record<string, unknown>[]>([]);
145→  const [meta, setMeta] = useState<Array<{ name: string; type?: string }>>([]);
146→  const [isLoading, setIsLoading] = useState(initialLoading);
147→  const [error, setError] = useState("");
148→  const [errorCode, setErrorCode] = useState<string>("");
149→  const [executedSql, setExecutedSql] = useState<string>("");
150→
151→  // Secondary data state (for Stat comparison)
152→  const [secondaryData, setSecondaryData] = useState<Record<string, unknown>[]>([]);
153→  const [isSecondaryLoading, setIsSecondaryLoading] = useState(false);
154→  const [secondaryError, setSecondaryError] = useState("");
155→
156→  // Inlined refreshable state (from useRefreshable hook)
157→  const [isCollapsed, setIsCollapsedInternal] = useState(typedDescriptor.collapsed ?? false);
158→  const [needRefresh, setNeedRefresh] = useState(false);
159→  const [isVisualizationMounted, setIsVisualizationMounted] = useState(false);
160→
161→  // Refs
162→  const apiCancellerRef = useRef<AbortController | null>(null);
163→  const secondaryApiCancellerRef = useRef<AbortController | null>(null);
164→
165→  const visualizationRef = useCallback((node: VisualizationRef | null) => {
166→    if (node) {
167→      // Visualization component has mounted
168→      visualizationRefInternal.current = node;
169→      setIsVisualizationMounted(true);
170→    }
171→  }, []);
172→
173→  const visualizationRefInternal = useRef<VisualizationRef>(null);
174→
175→  const lastRefreshParamRef = useRef<RefreshOptions>({});
176→
177→  // Inlined refreshable refs (from useRefreshable hook)
178→  const componentRef = useRef<HTMLDivElement>(null);
179→  const observerRef = useRef<IntersectionObserver | null>(null);
180→  const refreshParameterRef = useRef<RefreshOptions | undefined>(undefined);
181→  const lastRefreshParamRefFromHook = useRef<RefreshOptions | undefined>(undefined);
182→
183→  // Skeleton timing state - simple show/hide with minimum display time
184→  const [showSkeleton, setShowSkeleton] = useState(false);
185→  const skeletonStartTimeRef = useRef<number | null>(null);
186→
187→  // Wrapper around setIsCollapsed that also calls the callback (from useRefreshable)
188→  const setIsCollapsed = useCallback(
189→    (collapsed: boolean) => {
190→      setIsCollapsedInternal(collapsed);
191→      onCollapsedChange?.(collapsed);
192→    },
193→    [onCollapsedChange]
194→  );
195→
196→  // Check if component is actually visible (from useRefreshable)
197→  const isComponentInView = useCallback((): boolean => {
198→    if (!componentRef.current) {
199→      return false;
200→    }
201→
202→    const element = componentRef.current;
203→
204→    // Check if element is actually visible (not hidden by collapsed parents)
205→    const rect = element.getBoundingClientRect();
206→    const isVisible = rect.width > 0 && rect.height > 0;
207→
208→    if (!isVisible) {
209→      return false;
210→    }
211→
212→    // Check if any parent is hidden (collapsed)
213→    let parent: HTMLElement | null = element.parentElement;
214→    while (parent && parent !== document.body) {
215→      const style = window.getComputedStyle(parent);
216→      if (style.display === "none" || style.visibility === "hidden") {
217→        return false;
218→      }
219→      if (parent.hasAttribute("hidden")) {
220→        return false;
221→      }
222→      if (parent.hasAttribute("data-state") && parent.getAttribute("data-state") === "closed") {
223→        if (style.display === "none") {
224→          return false;
225→        }
226→      }
227→      parent = parent.parentElement;
228→    }
229→
230→    // Check if element is in viewport
231→    const viewportHeight = window.innerHeight || document.documentElement.clientHeight;
232→    const elementBottom = rect.bottom;
233→    const elementTop = rect.top;
234→
235→    return elementTop < viewportHeight && elementBottom > 0;
236→  }, []);
237→
238→  // Check if component should refresh (from useRefreshable)
239→  const shouldRefresh = useCallback((): boolean => {
240→    return !isCollapsed && isComponentInView();
241→  }, [isCollapsed, isComponentInView]);
242→
243→  // Load data function - unified for all types
244→  const loadData = useCallback(
245→    async (param: RefreshOptions, pageNumber: number = 0) => {
246→      if (!connection) {
247→        return;
248→      }
249→
250→      const query = typedDescriptor.datasource;
251→      if (!query) {
252→        return;
253→      }
254→
255→      setIsLoading(true);
256→      // Don't clear error here - only clear it when we successfully get data
257→      // This prevents flickering when refreshing a chart that has an error
258→
259→      // Cancel previous request if any
260→      if (apiCancellerRef.current) {
261→        apiCancellerRef.current.abort();
262→        apiCancellerRef.current = null;
263→      }
264→
265→      try {
266→        lastRefreshParamRef.current = param;
267→
268→        // Build SQL query with all replacements
269→        // Cluster template replacement is now handled by connection.query()
270→        const timezone = connection.metadata?.timezone || "UTC";
271→        let finalSql = new SQLQueryBuilder(query.sql)
272→          .timeSpan(param.timeSpan, timezone)
273→          .filterExpression(param.filterExpression)
274→          .build();
275→
276→        // Let visualization component prepare SQL (e.g., table adds ORDER BY and pagination)
277→        // With the callback ref pattern, visualizationRefInternal.current will be available
278→        // before the initial data load is triggered
279→        if (visualizationRefInternal.current?.prepareDataFetchSql) {
280→          finalSql = visualizationRefInternal.current.prepareDataFetchSql(finalSql, pageNumber);
281→        }
282→
283→        setExecutedSql(finalSql);
284→
285→        // Choose the right query method based on type
286→        const { response, abortController } = connection.queryOnNode(
287→          finalSql,
288→          {
289→            default_format: "JSON",
290→            output_format_json_quote_64bit_integers: 0,
291→            ...query.params,
292→          },
293→          {
294→            "Content-Type": "text/plain",
295→            ...query.headers,
296→          }
297→        );
298→        apiCancellerRef.current = abortController;
299→
300→        const apiResponse = await response;
301→
302→        if (abortController.signal.aborted) {
303→          setIsLoading(false);
304→          return;
305→        }
306→
307→        const responseData = apiResponse.data.json<{
308→          data?: Record<string, unknown>[];
309→          meta?: { name: string; type?: string }[];
310→        }>();
311→
312→        const newData = responseData.data || [];
313→        const newMeta = responseData.meta || [];
314→
315→        // Handle data based on type
316→        if (pageNumber === 0) {
317→          // First page - replace data (keep synchronous for immediate feedback)
318→          setData(newData);
319→          setMeta(newMeta);
320→        } else {
321→          // Subsequent pages - append data using transition for non-blocking update
322→          // This prevents UI freezing and allows progress bar to animate smoothly
323→          startTransition(() => {
324→            setData((prevData) => [...prevData, ...newData]);
325→          });
326→        }
327→
328→        // Clear error on successful data load
329→        setError("");
330→        setErrorCode("");
331→        setIsLoading(false);
332→
333→        // Handle Stat comparison if needed
334→        if (typedDescriptor.type === "stat") {
335→          const statDescriptor = typedDescriptor as StatDescriptor;
336→          if (statDescriptor.comparisonOption?.offset && props.initialTimeSpan) {
337→            const offsetValue = DateTimeExtension.parseOffsetExpression(
338→              statDescriptor.comparisonOption.offset
339→            );
340→
341→            if (offsetValue !== 0) {
342→              setIsSecondaryLoading(true);
343→              setSecondaryError("");
344→
345→              if (secondaryApiCancellerRef.current) {
346→                secondaryApiCancellerRef.current.abort();
347→                secondaryApiCancellerRef.current = null;
348→              }
349→
350→              // Calculate offset time span
351→              const offsetTimeSpan: TimeSpan = {
352→                startISO8601:
353→                  DateTimeExtension.formatISO8601(
354→                    new Date(
355→                      new Date(props.initialTimeSpan.startISO8601).getTime() + offsetValue * 1000
356→                    )
357→                  ) || "",
358→
359→                endISO8601:
360→                  DateTimeExtension.formatISO8601(
361→                    new Date(
362→                      new Date(props.initialTimeSpan.endISO8601).getTime() + offsetValue * 1000
363→                    )
364→                  ) || "",
365→              };
366→
367→              // Prepare offset SQL with all replacements
368→              const offsetSql = new SQLQueryBuilder(query.sql)
369→                .timeSpan(offsetTimeSpan, timezone)
370→                .filterExpression(param.filterExpression)
371→                .build();
372→
373→              const { response: offsetResponse, abortController: offsetAbort } =
374→                connection.queryOnNode(
375→                  offsetSql,
376→                  {
377→                    default_format: "JSON",
378→                    output_format_json_quote_64bit_integers: 0,
379→                    ...query.params,
380→                  },
381→                  {
382→                    "Content-Type": "text/plain",
383→                    ...query.headers,
384→                  }
385→                );
386→
387→              secondaryApiCancellerRef.current = offsetAbort;
388→
389→              offsetResponse
390→                .then((res) => {
391→                  if (offsetAbort.signal.aborted) return;
392→
393→                  if (res.httpStatus >= 400) {
394→                    const errData = res.data.json<QueryError>();
395→                    const message = errData.message || "Failed to load comparison data";
396→                    setSecondaryError(normalizeVisualizationError(message));
397→                  } else {
398→                    const resData = res.data.json<{
399→                      data?: Record<string, unknown>[];
400→                    }>();
401→                    setSecondaryData(resData.data || []);
402→                  }
403→                  setIsSecondaryLoading(false);
404→                })
405→                .catch((err) => {
406→                  if (offsetAbort.signal.aborted) return;
407→                  const message = err instanceof Error ? err.message : "Unknown error";
408→                  setSecondaryError(normalizeVisualizationError(message));
409→                  setIsSecondaryLoading(false);
410→                });
411→            }
412→          }
413→        }
414→      } catch (err) {
415→        if (err instanceof Error && err.name === "AbortError") {
416→          return;
417→        }
418→        if (err instanceof QueryError) {
419→          setError(normalizeVisualizationError(String(err.data || err.message)));
420→          setErrorCode(err.errorCode || "");
421→        } else {
422→          const message = err instanceof Error ? err.message : "Unknown error";
423→          setError(normalizeVisualizationError(message));
424→          //setErrorCode("");
425→        }
426→        setIsLoading(false);
427→      }
428→    },
429→    [connection, typedDescriptor, props.initialTimeSpan]
430→  );
431→
432→  // Internal refresh function
433→  const refreshInternal = useCallback(
434→    (param: RefreshOptions) => {
435→      if (!typedDescriptor.datasource) {
436→        return;
437→      }
438→
439→      // Reset pagination state on refresh (if visualization supports it)
440→      visualizationRefInternal.current?.resetPagination?.();
441→
442→      loadData(param, 0);
443→    },
444→    [typedDescriptor.datasource, loadData]
445→  );
446→
447→  // Public refresh method (from useRefreshable, modified to check visualization ref)
448→  const refresh = useCallback(
449→    (param: RefreshOptions) => {
450→      // Check if the parameters have actually changed
451→      if (
452→        !param.forceRefresh &&
453→        lastRefreshParamRefFromHook.current &&
454→        JSON.stringify(lastRefreshParamRefFromHook.current) === JSON.stringify(param)
455→      ) {
456→        return;
457→      }
458→
459→      // Store the parameter for potential deferred execution
460→      refreshParameterRef.current = param;
461→
462→      // Re-check visibility at the time of refresh
463→      const isCurrentlyVisible = isComponentInView();
464→      const shouldRefreshNow = !isCollapsed && isCurrentlyVisible;
465→
466→      // Only refresh if NOT collapsed AND in viewport
467→      if (shouldRefreshNow) {
468→        refreshInternal(param);
469→        lastRefreshParamRefFromHook.current = param;
470→        setNeedRefresh(false);
471→      } else {
472→        // Mark that refresh is needed when component becomes visible/expanded
473→        setNeedRefresh(true);
474→        // Set isLoading to false since we're not actually loading anything yet
475→        // This prevents the skeleton from showing forever for collapsed panels
476→        setIsLoading(false);
477→      }
478→    },
479→    [isCollapsed, isComponentInView, refreshInternal]
480→  );
481→
482→  const getLastRefreshParameter = useCallback((): RefreshOptions => {
483→    return refreshParameterRef.current || {};
484→  }, []);
485→
486→  // Expose component ref
487→  useImperativeHandle(ref, () => ({
488→    refresh,
489→    getLastRefreshParameter,
490→    getLastRefreshOptions: getLastRefreshParameter, // Alias for compatibility
491→  }));
492→
493→  // Table-specific handlers
494→  const handleSortChange = useCallback(
495→    (column: string, direction: "asc" | "desc" | null) => {
496→      if (typedDescriptor.type !== "table") return;
497→
498→      const tableDescriptor = typedDescriptor as TableDescriptor;
499→      if (tableDescriptor.sortOption?.serverSideSorting) {
500→        const lastParams = lastRefreshParamRef.current;
501→        const refreshParam: RefreshOptions = {
502→          ...lastParams,
503→          forceRefresh: true,
504→        };
505→        refresh(refreshParam);
506→      }
507→    },
508→    [typedDescriptor, refresh]
509→  );
510→
511→  // Handle loading data for a specific page (called by table visualization)
512→  const handleLoadData = useCallback(
513→    async (pageNumber: number) => {
514→      if (typedDescriptor.type !== "table") return;
515→      await loadData(lastRefreshParamRef.current, pageNumber);
516→    },
517→    [typedDescriptor.type, loadData]
518→  );
519→
520→  // Common handlers
521→  const handleShowQuery = useCallback(() => {
522→    showQueryDialog(typedDescriptor.datasource, typedDescriptor.titleOption?.title, executedSql);
523→  }, [typedDescriptor.datasource, typedDescriptor.titleOption, executedSql]);
524→
525→  const handleRefresh = useCallback(() => {
526→    const lastParams = getLastRefreshParameter();
527→    refresh({ ...lastParams, forceRefresh: true });
528→  }, [getLastRefreshParameter, refresh]);
529→
530→  // Handler for showing raw data dialog (for timeseries)
531→  const handleShowRawData = useCallback(() => {
532→    if (data.length === 0) {
533→      Dialog.alert({
534→        title: "No Data",
535→        description: "There is no data to display.",
536→      });
537→      return;
538→    }
539→
540→    // Get columns from meta if available, otherwise from data keys
541→    const columns = meta.length > 0 ? meta.map((m) => m.name) : Object.keys(data[0] || {});
542→
543→    Dialog.showDialog({
544→      title: typedDescriptor.titleOption?.title || "Query Result",
545→      className: "max-w-[80vw]",
546→      mainContent: (
547→        <div className="overflow-auto max-h-[70vh]">
548→          <table className="w-full border-collapse">
549→            <thead className="sticky top-0 bg-background z-10">
550→              <tr className="border-b">
551→                {columns.map((colName) => (
552→                  <th key={colName} className="p-2 text-left whitespace-nowrap font-semibold">
553→                    {colName}
554→                  </th>
555→                ))}
556→              </tr>
557→            </thead>
558→            <tbody>
559→              {data.map((row, rowIndex) => (
560→                <tr key={rowIndex} className="border-b hover:bg-muted/50">
561→                  {columns.map((colName) => {
562→                    const value = row[colName];
563→                    const displayValue =
564→                      value === null || value === undefined ? "-" : String(value);
565→                    return (
566→                      <td key={colName} className="p-2 align-middle whitespace-nowrap">
567→                        {displayValue}
568→                      </td>
569→                    );
570→                  })}
571→                </tr>
572→              ))}
573→            </tbody>
574→          </table>
575→        </div>
576→      ),
577→    });
578→  }, [data, meta, typedDescriptor.titleOption?.title]);
579→
580→  // Handlers for custom dashboard edit/delete
581→  const handleEditThisPanel = useCallback(() => {
582→    if (!customDashboardActions) return;
583→    const index = customDashboardActions.getPanelIndex(descriptor);
584→    if (index >= 0) customDashboardActions.onEditPanel(index);
585→  }, [customDashboardActions, descriptor]);
586→
587→  const handleDeleteThisPanel = useCallback(() => {
588→    if (!customDashboardActions) return;
589→    const index = customDashboardActions.getPanelIndex(descriptor);
590→    if (index >= 0) customDashboardActions.onDeletePanel(index);
591→  }, [customDashboardActions, descriptor]);
592→
593→  // Get dropdown items - combine facade-level items with visualization-specific items
594→  const getDropdownItems = useCallback(() => {
595→    // Get visualization-specific dropdown items (without "Show query")
596→    const vizItems = visualizationRefInternal.current?.getDropdownItems();
597→
598→    // Combine with facade-level items
599→    return (
600→      <>
601→        {customDashboardActions && (
602→          <>
603→            <DashboardDropdownMenuItem onClick={handleEditThisPanel}>
604→              Edit panel
605→            </DashboardDropdownMenuItem>
606→            <DashboardDropdownMenuItem
607→              className="text-destructive focus:text-destructive"
608→              onClick={handleDeleteThisPanel}
609→            >
610→              Delete panel
611→            </DashboardDropdownMenuItem>
612→            {(typedDescriptor.datasource?.sql || data.length > 0 || vizItems) && (
613→              <div className="my-1 h-px bg-border" />
614→            )}
615→          </>
616→        )}
617→        {typedDescriptor.datasource?.sql && (
618→          <DashboardDropdownMenuItem onClick={handleShowQuery}>
619→            Show query
620→          </DashboardDropdownMenuItem>
621→        )}
622→        {data.length > 0 && (
623→          <DashboardDropdownMenuItem onClick={handleShowRawData}>
624→            Show query result
625→          </DashboardDropdownMenuItem>
626→        )}
627→        {vizItems}
628→      </>
629→    );
630→  }, [typedDescriptor.datasource, handleShowQuery, data.length, handleShowRawData, customDashboardActions, handleEditThisPanel, handleDeleteThisPanel]);
631→
632→  // Render error state
633→  const renderError = () => (
634→    <div className="flex h-full w-full flex-col items-center justify-center p-1 text-sm text-destructive gap-1">
635→      <AskAIButton sql={executedSql} errorMessage={error} hideAfterClick={false} />
636→      <div className="text-center overflow-auto w-full max-h-full custom-scrollbar">{error}</div>
637→    </div>
638→  );
639→
640→  // Track first load state (when data is empty and loading)
641→  const isFirstLoad = data.length === 0 && isLoading && !error;
642→
643→  // Simple skeleton timing: handle minimum display time, CSS handles fade
644→  useEffect(() => {
645→    if (isFirstLoad) {
646→      // Start showing skeleton
647→      if (skeletonStartTimeRef.current === null) {
648→        skeletonStartTimeRef.current = Date.now();
649→        setShowSkeleton(true);
650→      }
651→    } else {
652→      // Data loaded - wait for minimum time if needed, then hide (CSS handles fade)
653→      if (skeletonStartTimeRef.current !== null) {
654→        const elapsed = Date.now() - skeletonStartTimeRef.current;
655→
656→        // Use a random so that different panels on the page will be shown in a random delay
657→        const remainingTime = Math.random() * Math.max(0, SKELETON_MIN_DISPLAY_TIME - elapsed);
658→
659→        setTimeout(() => {
660→          setShowSkeleton(false);
661→          skeletonStartTimeRef.current = null;
662→        }, remainingTime);
663→      }
664→    }
665→  }, [isFirstLoad]);
666→
667→  // Track if initial refresh has been done
668→  const initialRefreshDoneRef = useRef(false);
669→
670→  // Trigger initial refresh AFTER visualization ref is available (modified from useRefreshable)
671→  // This effect only handles the INITIAL refresh - subsequent refreshes are triggered via the imperative handle
672→  useEffect(() => {
673→    if (!initialLoading) {
674→      return;
675→    }
676→
677→    // Wait for visualization to be mounted before initial refresh
678→    if (!isVisualizationMounted) {
679→      return;
680→    }
681→
682→    // Only do initial refresh once
683→    if (initialRefreshDoneRef.current) {
684→      return;
685→    }
686→
687→    // Check if the query requires time span parameters
688→    const query = typedDescriptor.datasource;
689→    const requiresTimeSpan =
690→      query?.sql.includes("{startTimestamp") ||
691→      query?.sql.includes("{endTimestamp") ||
692→      query?.sql.includes("{timeFilter") ||
693→      query?.sql.includes("{from:") ||
694→      query?.sql.includes("{to:");
695→
696→    if (requiresTimeSpan && !props.initialTimeSpan) {
697→      // Skip initial refresh when time span is required but not available
698→      return;
699→    }
700→
701→    initialRefreshDoneRef.current = true;
702→
703→    // Use props directly to ensure we get the current values
704→    const params: RefreshOptions = {
705→      timeSpan: props.initialTimeSpan,
706→      filterExpression: props.initialFilterExpression ?? "1=1",
707→    };
708→
709→    // Trigger refresh with params
710→    refresh(params);
711→  }, [
712→    isVisualizationMounted,
713→    props.initialTimeSpan,
714→    props.initialFilterExpression,
715→    typedDescriptor.datasource,
716→    refresh,
717→  ]);
718→
719→  // Keep refresh parameters in sync with props
720→  useEffect(() => {
721→    refreshParameterRef.current = {
722→      ...refreshParameterRef.current,
723→      timeSpan: props.initialTimeSpan,
724→      filterExpression: props.initialFilterExpression,
725→    };
726→  }, [props.initialTimeSpan, props.initialFilterExpression]);
727→
728→  // Handle collapsed state changes - refresh when expanded if needed (from useRefreshable)
729→  useEffect(() => {
730→    if (!isCollapsed && needRefresh && shouldRefresh()) {
731→      const currentParam = refreshParameterRef.current;
732→      if (currentParam) {
733→        if (
734→          lastRefreshParamRefFromHook.current &&
735→          JSON.stringify(lastRefreshParamRefFromHook.current) === JSON.stringify(currentParam)
736→        ) {
737→          setNeedRefresh(false);
738→        } else {
739→          refreshInternal(currentParam);
740→          lastRefreshParamRefFromHook.current = currentParam;
741→          setNeedRefresh(false);
742→        }
743→      } else {
744→        setNeedRefresh(false);
745→      }
746→    }
747→  }, [isCollapsed, needRefresh, shouldRefresh, refreshInternal]);
748→
749→  // IntersectionObserver setup (from useRefreshable)
750→  useEffect(() => {
751→    const handleIntersection = (entries: IntersectionObserverEntry[]) => {
752→      const entry = entries[0];
753→      if (entry.isIntersecting && entry.intersectionRatio > 0 && shouldRefresh()) {
754→        if (!isComponentInView()) {
755→          return;
756→        }
757→
758→        const currentParam = refreshParameterRef.current;
759→        if (currentParam) {
760→          if (
761→            lastRefreshParamRefFromHook.current &&
762→            JSON.stringify(lastRefreshParamRefFromHook.current) === JSON.stringify(currentParam)
763→          ) {
764→            setNeedRefresh(false);
765→          } else {
766→            refreshInternal(currentParam);
767→            lastRefreshParamRefFromHook.current = currentParam;
768→            setNeedRefresh(false);
769→          }
770→        }
771→      }
772→    };
773→
774→    const currentComponent = componentRef.current;
775→    observerRef.current = new IntersectionObserver(handleIntersection, {
776→      root: null,
777→      rootMargin: "0px",
778→      threshold: [0, 0.1],
779→    });
780→
781→    if (currentComponent) {
782→      observerRef.current.observe(currentComponent);
783→    }
784→
785→    return () => {
786→      if (currentComponent && observerRef.current) {
787→        observerRef.current.unobserve(currentComponent);
788→      }
789→    };
790→  }, [needRefresh, shouldRefresh, refreshInternal, isComponentInView]);
791→
792→  // Defensive check - after all hooks
793→  if (!descriptor || !descriptor.type) {
794→    return <pre>Invalid descriptor: {JSON.stringify(descriptor, null, 2)}</pre>;
795→  }
796→
797→  return (
798→    <DashboardVisualizationLayout
799→      componentRef={componentRef}
800→      className={props.className}
801→      isLoading={isLoading}
802→      titleOption={typedDescriptor.titleOption}
803→      getDropdownItems={getDropdownItems}
804→      onRefresh={handleRefresh}
805→    >
806→      <div className="h-full w-full">
807→        {showSkeleton ? (
808→          <div className="flex items-center justify-center h-full w-full min-h-[100px] transition-opacity duration-150">
809→            <Skeleton className="w-full h-full [animation-duration:1s]" />
810→          </div>
811→        ) : (
812→          <div className="h-full w-full transition-opacity duration-150">
813→            {error ? (
814→              ErrorComponent({
815→                error,
816→                errorCode,
817→                executedSql,
818→                shouldShowAskAI: error !== "no metrics",
819→              })
820→            ) : typedDescriptor.type === "table" ? (
821→              <TableVisualization
822→                ref={visualizationRef as React.Ref<TableVisualizationRef>}
823→                data={data}
824→                meta={meta}
825→                descriptor={typedDescriptor as TableDescriptor}
826→                selectedTimeSpan={props.initialTimeSpan}
827→                isLoading={isLoading}
828→                onSortChange={handleSortChange}
829→                onLoadData={handleLoadData}
830→              />
831→            ) : typedDescriptor.type === "pie" ? (
832→              <PieVisualization
833→                ref={visualizationRef as React.Ref<PieVisualizationRef>}
834→                data={data}
835→                meta={meta}
836→                descriptor={typedDescriptor as PieDescriptor}
837→                selectedTimeSpan={props.initialTimeSpan}
838→              />
839→            ) : typedDescriptor.type === "transpose-table" ? (
840→              <TransposeTableVisualization
841→                ref={visualizationRef as React.Ref<TransposeTableVisualizationRef>}
842→                data={data}
843→                descriptor={typedDescriptor as TransposeTableDescriptor}
844→              />
845→            ) : typedDescriptor.type === "line" ||
846→              typedDescriptor.type === "bar" ||
847→              typedDescriptor.type === "area" ? (
848→              <TimeseriesVisualization
849→                ref={visualizationRef as React.Ref<TimeseriesVisualizationRef>}
850→                data={data}
851→                meta={meta}
852→                descriptor={typedDescriptor as TimeseriesDescriptor}
853→                selectedTimeSpan={props.initialTimeSpan}
854→                onChartSelection={props.onChartSelection}
855→              />
856→            ) : typedDescriptor.type === "gauge" ? (
857→              <GaugeVisualization
858→                ref={visualizationRef as React.Ref<GaugeVisualizationRef>}
859→                data={data}
860→                meta={meta}
861→                descriptor={typedDescriptor as GaugeDescriptor}
862→                selectedTimeSpan={props.initialTimeSpan}
863→              />
864→            ) : typedDescriptor.type === "stat" ? (
865→              <StatVisualization
866→                ref={visualizationRef as React.Ref<StatVisualizationRef>}
867→                data={data}
868→                meta={meta}
869→                secondaryData={secondaryData}
870→                descriptor={typedDescriptor as StatDescriptor}
871→                selectedTimeSpan={props.initialTimeSpan}
872→                isSecondaryLoading={isSecondaryLoading}
873→                secondaryError={secondaryError}
874→                isLoading={isLoading}
875→              />
876→            ) : null}
877→          </div>
