// Keep sqlRef in sync
sqlRef.current = sql;

const runQuery = useCallback(() => {
  const descriptor = buildDescriptorFromState(
    chartType,
    title,
    sql,
    gridW,
    gridH,
    statOptions,
    timeseriesOptions,
    pieOptions,
    gaugeOptions,
    tableOptions,
    originalDescriptorRef.current
  );
  setPreviewDescriptor(descriptor);
  setPreviewKey((k) => k + 1);
  hasPreviewRef.current = true;
}, [
  chartType,
  title,
  sql,
  gridW,
  gridH,
  statOptions,
  timeseriesOptions,
  pieOptions,
  gaugeOptions,
  tableOptions,
]);

// Auto-update preview when visual options change (without re-running the query).
// SQL changes are excluded — the user must click "Run Query" to re-fetch data.
useEffect(() => {
  if (!hasPreviewRef.current) return;

  const updated = buildDescriptorFromState(
    chartType,
    title,
    sqlRef.current,
    gridW,
    gridH,
    statOptions,
    timeseriesOptions,
    pieOptions,
    gaugeOptions,
    tableOptions,
    originalDescriptorRef.current
  );
  setPreviewDescriptor(updated);
}, [
  chartType,
  title,
  gridW,
  gridH,
  statOptions,
  timeseriesOptions,
  pieOptions,
  gaugeOptions,
  tableOptions,
]);

