    (partial: Partial<GaugeOptions>) => {
      setGaugeOptions((prev) => ({ ...prev, ...partial }));
      markDirty();
    },
    [markDirty]
  );

  const updateTableOptions = useCallback(
    (partial: Partial<TableOptions>) => {
      setTableOptions((prev) => ({ ...prev, ...partial }));
      markDirty();
    },
    [markDirty]
  );

  const runQuery = useCallback(() => {
    const descriptor = buildDescriptorFromState(
      chartType,
      title,
      sql,
      gridW,
      gridH,
      statOptions,
      timeseriesOptions,
      pieOptions,
      gaugeOptions,
      tableOptions,
      originalDescriptorRef.current
    );
    setPreviewDescriptor(descriptor);
    setPreviewKey((k) => k + 1);
  }, [
    chartType,
    title,
    sql,
    gridW,
    gridH,
    statOptions,
    timeseriesOptions,
    pieOptions,
    gaugeOptions,
    tableOptions,
  ]);

  const buildDescriptor = useCallback((): PanelDescriptor | null => {
    if (!title.trim() || !sql.trim()) return null;
    return buildDescriptorFromState(
      chartType,
      title,
      sql,
      gridW,
      gridH,
      statOptions,
      timeseriesOptions,
      pieOptions,
      gaugeOptions,
      tableOptions,
      originalDescriptorRef.current
    );
  }, [
    chartType,
    title,
    sql,
    gridW,
    gridH,
    statOptions,
    timeseriesOptions,
    pieOptions,
    gaugeOptions,
    tableOptions,
  ]);

